import{c as a,Q as e,j as n,m as o}from"./chunks/framework.BXc4yaFE.js";const h=JSON.parse('{"title":"Stop Using /init for AGENTS.md","description":"","frontmatter":{"url":"https://addyosmani.com/blog/agents-md/","title":"Stop Using /init for AGENTS.md","date":"2026-02-23T00:00:00.000Z","type":"article"},"headers":[],"relativePath":"research/ai-articles/scored/2026-02-23-addyosmani-agents-md.md","filePath":"research/ai-articles/scored/2026-02-23-addyosmani-agents-md.md","lastUpdated":1779894392000}'),r={name:"research/ai-articles/scored/2026-02-23-addyosmani-agents-md.md"};function s(i,t,l,d,c,p){return e(),n("div",null,[...t[0]||(t[0]=[o(`<h1 id="stop-using-init-for-agents-md" tabindex="-1">Stop Using /init for AGENTS.md <a class="header-anchor" href="#stop-using-init-for-agents-md" aria-label="Permalink to &quot;Stop Using /init for AGENTS.md&quot;">​</a></h1><p><strong>原始來源</strong>：<a href="https://addyosmani.com/blog/agents-md/" target="_blank" rel="noreferrer">https://addyosmani.com/blog/agents-md/</a><br><strong>作者</strong>：Addy Osmani<br><strong>發表日期</strong>：2026-02-23<br><strong>評分日期</strong>：2026-05-05</p><hr><h2 id="繁體中文全文摘要" tabindex="-1">繁體中文全文摘要 <a class="header-anchor" href="#繁體中文全文摘要" aria-label="Permalink to &quot;繁體中文全文摘要&quot;">​</a></h2><h3 id="tl-dr" tabindex="-1">TL;DR <a class="header-anchor" href="#tl-dr" aria-label="Permalink to &quot;TL;DR&quot;">​</a></h3><p>自動生成的 AGENTS.md 傷害 Agent 效能，增加成本 20% 以上。原因是 Agent 本來就能自己發現這些資訊，你只是讓它讀了兩遍。<strong>只有 Agent 無法自行推斷的資訊才值得一行。</strong></p><h3 id="研究發現-agents-md-有沒有用" tabindex="-1">研究發現：AGENTS.md 有沒有用？ <a class="header-anchor" href="#研究發現-agents-md-有沒有用" aria-label="Permalink to &quot;研究發現：AGENTS.md 有沒有用？&quot;">​</a></h3><p>兩項研究，結論看似矛盾，但實際揭示了更深的真相：</p><h4 id="lulla-et-al-icse-jaws-2026" tabindex="-1">Lulla et al.（ICSE JAWs 2026） <a class="header-anchor" href="#lulla-et-al-icse-jaws-2026" aria-label="Permalink to &quot;Lulla et al.（ICSE JAWs 2026）&quot;">​</a></h4><ul><li>124 個真實 GitHub PR，有無 AGENTS.md 對比</li><li><strong>結果</strong>：有 AGENTS.md → median 執行時間 -28.64%，輸出 token -16.58%</li><li><strong>但</strong>：這些是人類精心維護的文件，包含真實的項目特有知識</li></ul><h4 id="eth-zurich-研究" tabindex="-1">ETH Zurich 研究 <a class="header-anchor" href="#eth-zurich-研究" aria-label="Permalink to &quot;ETH Zurich 研究&quot;">​</a></h4><ul><li>測試 LLM 自動生成 vs. 開發者撰寫的 context 文件</li><li><strong>LLM 生成文件</strong>：task 成功率 -2~3%，成本 +20% 以上</li><li><strong>開發者撰寫文件</strong>：成功率 +4%，但成本也 +19%</li><li><strong>最關鍵發現</strong>：移除 repo 的所有文件後再測試，LLM 生成的 context 文件改善了 2.7%</li></ul><p><strong>統一解釋</strong>：自動生成的內容不是沒用，而是<strong>冗餘</strong>。Agent 能自己找到這些資訊。給它同樣的資訊兩次 = 噪音。</p><h3 id="粉象問題-anchoring-effect" tabindex="-1">粉象問題（Anchoring Effect） <a class="header-anchor" href="#粉象問題-anchoring-effect" aria-label="Permalink to &quot;粉象問題（Anchoring Effect）&quot;">​</a></h3><p>AGENTS.md 中提到的任何技術/模式都會在每個提示詞中影響模型。若你提到已廢棄的框架，模型會傾向於使用它。<strong>「Lost in the Middle」效應（Liu et al. 2024）</strong>：放在 context 中間的資訊更容易被忽略，但放在 AGENTS.md 的資訊卻會無差別地影響每個任務。</p><h3 id="init-的核心問題" tabindex="-1">/init 的核心問題 <a class="header-anchor" href="#init-的核心問題" aria-label="Permalink to &quot;/init 的核心問題&quot;">​</a></h3><p>100% 的 Sonnet 4.5 自動生成文件都包含 codebase 概覽。99% 的 GPT-5.2 也是如此。這些正好是 Agent 通過 <code>ls</code> 和讀取 README 就能自己找到的東西。</p><p><strong>實際效果</strong>：Agent 讀取 AGENTS.md → 去讀真實代碼確認 → 需要協調兩個資訊來源 → 更多 token，更慢，同樣結果。</p><h3 id="什麼真正值得寫入-agents-md" tabindex="-1">什麼真正值得寫入 AGENTS.md <a class="header-anchor" href="#什麼真正值得寫入-agents-md" aria-label="Permalink to &quot;什麼真正值得寫入 AGENTS.md&quot;">​</a></h3><p>ETH Zurich 研究的具體發現：</p><ul><li>當 context 文件提到 <code>uv</code>（套件管理器）→ Agent 使用頻率：1.6 次/任務</li><li>不提及 → 使用頻率：&lt; 0.01 次/任務</li></ul><p><strong>判斷標準</strong>：<code>uv</code> vs <code>pip</code> 的區別符合三條件：</p><ol><li>代碼庫中無法直接發現</li><li>操作上有重大影響（改變執行的命令）</li><li>Agent 無法透過慣例推斷</li></ol><p>對比「專案使用 monorepo 結構，packages 在 /packages 下」—— 第一個 <code>ls</code> 就能找到。</p><p><strong>理想 AGENTS.md 範例</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- 使用 uv 進行套件管理</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- 永遠用 --no-cache 跑測試，否則 fixture 設定會有假陽性</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- auth 模組使用自定義 middleware，勿重構為標準 Express middleware</span></span>
<span class="line"><span></span></span>
<span class="line"><span>- legacy/ 目錄已棄用但被三個生產模組引用，不要刪除其中任何東西</span></span></code></pre></div><h3 id="靜態文件問題" tabindex="-1">靜態文件問題 <a class="header-anchor" href="#靜態文件問題" aria-label="Permalink to &quot;靜態文件問題&quot;">​</a></h3><p>一個扁平的指令集無法針對任務類型做條件判斷：</p><ul><li>Agent 做 CSS 重構時不需要看資料庫遷移警告</li><li>Agent 實作安全修復時可能應該跳過效能優化提示</li></ul><p><strong>ACE 框架（ICLR 2026）</strong> 透過 generator/reflector/curator pipeline 把 context 當成動態演進的 playbook，超越靜態文件 <strong>12.3%</strong>。</p><h3 id="正確架構" tabindex="-1">正確架構 <a class="header-anchor" href="#正確架構" aria-label="Permalink to &quot;正確架構&quot;">​</a></h3><p><strong>Layer 1（Protocol File）</strong>：AGENTS.md 的本質 — routing 文件，不是概覽</p><ul><li>可用角色與何時調用</li><li>可用 skills 與任務類別</li><li>Agent 真正無法發現的最小必要 repo 事實</li></ul><p><strong>Layer 2（Focused persona/skill files）</strong>：依任務類型選擇性載入</p><p><strong>Layer 3（維護 Sub-agent）</strong>：唯一職責是保持 protocol file 準確</p><h3 id="正確心態" tabindex="-1">正確心態 <a class="header-anchor" href="#正確心態" aria-label="Permalink to &quot;正確心態&quot;">​</a></h3><p>把 AGENTS.md 當成「<strong>你還沒修好的磨擦點列表</strong>」：</p><ul><li>Agent 一直把工具放錯目錄 → 目錄結構有問題，應重組</li><li>Agent 一直用廢棄 dependency → import 結構讓錯誤的那個太容易被抓到</li><li>Agent 忘記跑 type check → build pipeline 應該自動捕捉</li></ul><p>每一行 AGENTS.md 都是你尚未修好的技術債的信號，而非永久配置。</p><h3 id="對-workspace-的啟示" tabindex="-1">對 Workspace 的啟示 <a class="header-anchor" href="#對-workspace-的啟示" aria-label="Permalink to &quot;對 Workspace 的啟示&quot;">​</a></h3><ol><li><strong>CLAUDE.md 應是目錄，不是百科全書</strong>：與 OpenAI Codex 文章的發現一致</li><li><strong><code>@-import</code> 按需載入策略是正確的</strong>：不同任務載入不同 rules，已在 cc-workspace 實踐</li><li><strong>60 行以下的 CLAUDE.md 是目標</strong>：過長的 CLAUDE.md = 警示信號，應提取到 refs/</li><li><strong>Agent 反覆犯同樣的錯 → 先改代碼，再改 AGENTS.md</strong>：這條原則應納入 haiku-pilot 的 Known Gotchas</li></ol><hr><h2 id="評分摘要" tabindex="-1">評分摘要 <a class="header-anchor" href="#評分摘要" aria-label="Permalink to &quot;評分摘要&quot;">​</a></h2><table tabindex="0"><thead><tr><th>維度</th><th>分數</th><th>理由</th></tr></thead><tbody><tr><td>A. Workspace 可行動性</td><td>9/10</td><td>直接影響 CLAUDE.md 設計策略，「靜態 vs 動態載入」是 cc-workspace 的核心架構決策</td></tr><tr><td>B. 創新性</td><td>7/10</td><td>反直覺結論（/init 有害）和粉象問題是新穎洞見；但整合現有研究而非原創</td></tr><tr><td>C. 證據品質</td><td>7/10</td><td>引用兩篇有量化數據的獨立研究；本文本身是 blog，非原始研究</td></tr><tr><td>D. 技術深度</td><td>7/10</td><td>三層架構方案具體，<code>uv</code> 案例有說服力，但 ACE 框架只是提及未深入</td></tr><tr><td>E. 泛化性</td><td>8/10</td><td>適用所有使用 agent 配置文件的項目，不限 Claude Code</td></tr><tr><td><strong>加權總分</strong></td><td><strong>7.75/10</strong></td><td>9×0.3 + 7×0.2 + 7×0.2 + 7×0.15 + 8×0.15 = 2.7+1.4+1.4+1.05+1.2</td></tr></tbody></table><p><strong>整合決策</strong>：Rule<br><strong>整合位置</strong>：<code>.claude/refs/anthropic-insights.md</code> 或 <code>.claude/rules/core.md</code><br><strong>整合狀態</strong>：待實作</p><p><strong>TODO</strong>：</p><ul><li>在 CLAUDE.md 加入「每行 CLAUDE.md 都是尚未修好的摩擦點」的指導原則</li><li>haiku-pilot Known Gotchas 補充：「Agent 反覆同一錯誤時，先看代碼結構，再加 context」</li></ul>`,47)])])}const u=a(r,[["render",s]]);export{h as __pageData,u as default};
